content:
{
  "sentences": [
    {
      "text": "今天天氣有點冷，我有點不想出門。",
      "pinyin": "Jīntiān tiānqì yǒudiǎn lěng, wǒ yǒudiǎn bù xiǎng chūmén.",
      "pinyin_numeric": "jin1tian1 tian1qi4 you3dian3 leng3, wo3 you3dian3 bu4 xiang3 chu1men2.",
      "translation_en": "The weather is a bit cold today, so I don't really feel like going out.",
      "translation_ko": "오늘 날씨가 좀 추워서, 나가기가 좀 싫어요."
    },
    {
      "text": "下雨天我有點悶，心情不太好。",
      "pinyin": "Xiàyǔ tiān wǒ yǒudiǎn mēn, xīnqíng bù tài hǎo.",
      "pinyin_numeric": "xia4yu3 tian1 wo3 you3dian3 men1, xin1qing2 bu4 tai4 hao3.",
      "translation_en": "On rainy days I feel a bit stuffy, and my mood isn't very good.",
      "translation_ko": "비 오는 날에는 좀 답답해서 기분이 별로 좋지 않아요."
    },
    {
      "text": "出太陽了，我有點開心，想出去走走。",
      "pinyin": "Chū tàiyáng le, wǒ yǒudiǎn kāixīn, xiǎng chūqù zǒuzǒu.",
      "pinyin_numeric": "chu1 tai4yang2 le0, wo3 you3dian3 kai1xin1, xiang3 chu1qu4 zou3zou3.",
      "translation_en": "The sun came out, I feel a bit happy and want to go out for a walk.",
      "translation_ko": "해가 나서 좀 기분이 좋아요, 밖에 나가서 산책하고 싶어요."
    },
    {
      "text": "颱風要來了，我有點緊張，需要買東西。",
      "pinyin": "Táifēng yào lái le, wǒ yǒudiǎn jǐnzhāng, xūyào mǎi dōngxī.",
      "pinyin_numeric": "tai2feng1 yao4 lai2 le0, wo3 you3dian3 jin3zhang1, xu1yao4 mai3 dong1xi1.",
      "translation_en": "A typhoon is coming, I'm a bit nervous and need to buy some things.",
      "translation_ko": "태풍이 오려고 해서 좀 긴장돼요, 물건을 사야 해요."
    },
    {
      "text": "今天三十度，天氣很熱，我有點不舒服。",
      "pinyin": "Jīntiān sānshí dù, tiānqì hěn rè, wǒ yǒudiǎn bù shūfu.",
      "pinyin_numeric": "jin1tian1 san1shi2 du4, tian1qi4 hen3 re4, wo3 you3dian3 bu4 shu1fu5.",
      "translation_en": "Today is 30 degrees, the weather is very hot, and I feel a bit uncomfortable.",
      "translation_ko": "오늘은 30도인데 날씨가 너무 더워서 좀 불편해요."
    },
    {
      "text": "陰天我有點沒精神，想在家休息。",
      "pinyin": "Yīntiān wǒ yǒudiǎn méi jīngshén, xiǎng zài jiā xiūxí.",
      "pinyin_numeric": "yin1tian1 wo3 you3dian3 mei2 jing1shen2, xiang3 zai4 jia1 xiu1xi2.",
      "translation_en": "On cloudy days I feel a bit low on energy and want to rest at home.",
      "translation_ko": "흐린 날에는 좀 기운이 없어서 집에서 쉬고 싶어요."
    },
    {
      "text": "天氣涼快，我有點放鬆，心情很好。",
      "pinyin": "Tiānqì liángkuài, wǒ yǒudiǎn fàngsōng, xīnqíng hěn hǎo.",
      "pinyin_numeric": "tian1qi4 liang2kuai4, wo3 you3dian3 fang4song1, xin1qing2 hen3 hao3.",
      "translation_en": "The weather is cool, I feel a bit relaxed, and my mood is great.",
      "translation_ko": "날씨가 시원해서 좀 편안해지고 기분이 좋아요."
    },
    {
      "text": "下雨路滑，我有點擔心，走路要小心。",
      "pinyin": "Xiàyǔ lù huá, wǒ yǒudiǎn dānxīn, zǒulù yào xiǎoxīn.",
      "pinyin_numeric": "xia4yu3 lu4 hua2, wo3 you3dian3 dan1xin1, zou3lu4 yao4 xiao3xin1.",
      "translation_en": "The road is slippery from the rain, I'm a bit worried and need to walk carefully.",
      "translation_ko": "비가 와서 길이 미끄러워요, 좀 걱정돼서 조심해서 걸어야 해요."
    },
    {
      "text": "今天多雲，我有點想喝咖啡，去咖啡店坐一下。",
      "pinyin": "Jīntiān duōyún, wǒ yǒudiǎn xiǎng hē kāfēi, qù kāfēi diàn zuò yīxià.",
      "pinyin_numeric": "jin1tian1 duo1yun2, wo3 you3dian3 xiang3 he1 ka1fei1, qu4 ka1fei1 dian4 zuo4 yi1xia4.",
      "translation_en": "Today is cloudy, I feel like having some coffee, so I'll go sit at a coffee shop for a bit.",
      "translation_ko": "오늘은 구름이 많아서 커피가 좀 마시고 싶어서 카페에 가서 잠깐 앉아 있을게요."
    },
    {
      "text": "颱風天風很大，我有點緊張，不想出門。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ yǒudiǎn jǐnzhāng, bù xiǎng chūmén.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 you3dian3 jin3zhang1, bu4 xiang3 chu1men2.",
      "translation_en": "On typhoon days the wind is strong, I'm a bit nervous and don't want to go out.",
      "translation_ko": "태풍이 오는 날에는 바람이 많이 불어서 좀 긴장돼서 밖에 나가고 싶지 않아요."
    }
  ]
}
